base_css:
/* Base Resets */
    body {
      margin: 0;
      font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      background-color: var(--bg-body);
      color: var(--text);
      overflow-x: hidden;
      padding-top: var(--header-h); 
    }
    @media (max-width: 991px) { body { padding-top: 64px; } }

    a { text-decoration: none; color: var(--primary); transition: color var(--t); }
    a:hover { color: var(--primary-2); }
    p { line-height: 1.7; color: var(--text-s); font-size: 0.95rem; }

    .font-syne { font-family: 'Syne', sans-serif; }

    /* ========================================================================== */
    /* COMPONENTS & TYPOGRAPHY                                                    */
    /* ========================================================================== */
    .section-title {
      position: relative; padding-bottom: .75rem; margin-bottom: 2rem;
      font-weight: 800; color: var(--primary-d); font-family: 'Syne', sans-serif;
      font-size: clamp(1.6rem, 4vw, 2.2rem);
    }
    .section-title::after {
      content: ''; position: absolute; bottom: 0; left: 0;
      width: 60px; height: 4px; border-radius: 2px;
      background: linear-gradient(90deg, var(--primary), var(--gold));
    }
    .section-title.center::after { left: 50%; transform: translateX(-50%); }

    .hover-lift { transition: transform 0.3s var(--ease), box-shadow 0.3s var(--ease), border-color 0.3s; }
    .hover-lift:hover { transform: translateY(-6px); box-shadow: var(--sh-md); border-color: rgba(51,133,255,0.15); z-index: 2; }

    /* ========================================================================== */
    /* HERO SECTION                                                               */
    /* ========================================================================== */
    .hero-banner {
      position: relative; overflow: hidden;
      background: linear-gradient(135deg, var(--digital-blue-950) 0%, var(--digital-blue-900) 50%, var(--digital-blue-800) 100%);
      padding: 80px 0 100px; text-align: center;
    }
    .hero-banner::before {
      content: ''; position: absolute; inset: 0;
      background-image: 
        radial-gradient(circle at 15% 50%, rgba(51, 133, 255, 0.2), transparent 30%),
        radial-gradient(circle at 85% 30%, rgba(51, 133, 255, 0.2), transparent 30%);
      z-index: 1; pointer-events: none;
    }
    .hero-ring {
      position: absolute; border-radius: 50%; border: 1px solid rgba(255,255,255,.05);
      pointer-events: none; z-index: 1;
    }
    .hero-ring-1 { width: 600px; height: 600px; top: -200px; left: -150px; border-color: rgba(51, 133, 255, 0.15); }
    .hero-ring-2 { width: 400px; height: 400px; bottom: -100px; right: -50px; border-color: rgba(255,255,255,.05); }

    .hero-content { position: relative; z-index: 3; max-width: 800px; margin: 0 auto; }
    .hero-breadcrumb {
      display: inline-flex; align-items: center; gap: 8px;
      color: var(--gold); font-size: .75rem; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em;
      background: rgba(51, 133, 255, 0.15); border: 1px solid rgba(51, 133, 255, 0.3);
      border-radius: 50px; padding: 6px 16px; margin-bottom: 24px;
      transition: all var(--t);
    }
    .hero-breadcrumb:hover { background: rgba(51, 133, 255, 0.25); color: #fff; transform: translateY(-2px); }
    .hero-banner h1 {
      font-size: clamp(2.5rem, 5vw, 3.8rem); font-weight: 800; color: #fff; 
      letter-spacing: -.02em; margin-bottom: 16px; text-shadow: 0 4px 20px rgba(0,0,0,0.3);
    }
    .hero-banner p {
      font-size: 1.15rem; color: rgba(255,255,255,.75); line-height: 1.7; margin-bottom: 0;
    }

    /* ========================================================================== */
    /* COMMITTEE CARDS (Styled like Event Cards)                                  */
    /* ========================================================================== */
    .cmt-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
      gap: 24px;
      margin-top: 40px;
    }

    .cmt-card {
      background: #fff;
      border-radius: 16px;
      overflow: hidden;
      border: 1px solid rgba(0,0,0,0.06);
      box-shadow: var(--sh-sm);
      transition: transform 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275), box-shadow 0.3s ease;
      cursor: pointer;
      display: flex;
      flex-direction: column;
      height: 100%;
    }
    .cmt-card:hover {
      transform: translateY(-8px);
      box-shadow: 0 16px 36px rgba(0,0,0,0.08);
      border-color: rgba(51,133,255,0.15);
    }

    .cmt-top {
      aspect-ratio: 21/9;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 3.5rem; 
      background-size: cover;
      background-position: center;
      background-color: var(--sur-2);
      border-bottom: 1px solid rgba(0,0,0,0.04);
    }
    .cmt-body {
      padding: 24px;
      display: flex;
      flex-direction: column;
      flex: 1;
    }

    .cmt-badge {
      font-size: 0.7rem;
      font-weight: 800;
      color: var(--primary-d);
      background: var(--digital-blue-50);
      padding: 4px 12px;
      border-radius: 50px;
      text-transform: uppercase;
      letter-spacing: 0.05em;
      display: inline-block;
      margin-bottom: 14px;
      align-self: flex-start;
    }

    .cmt-title {
      font-family: 'DM Sans', sans-serif;
      font-size: 1.25rem;
      font-weight: 800;
      color: var(--primary-d);
      margin-bottom: 16px;
      line-height: 1.35;
    }

    .cmt-preview-list {
      list-style: none;
      padding: 0; margin: 0 0 20px 0;
    }
    .cmt-preview-list li {
      font-size: 0.88rem;
      color: var(--text-s);
      padding: 8px 0;
      border-bottom: 1px solid var(--bdr-s);
      display: flex;
      justify-content: space-between;
      align-items: center;
    }
    .cmt-preview-list li:last-child { border-bottom: none; }
    .cmt-preview-role {
      font-size: 0.7rem;
      font-weight: 700;
      color: var(--text-m);
      background: var(--sur-2);
      padding: 2px 8px;
      border-radius: 8px;
    }

    .cmt-action {
      margin-top: auto;
      font-size: 0.85rem;
      color: var(--primary);
      font-weight: 700;
      display: flex;
      align-items: center;
      gap: 8px;
      border-top: 1px solid var(--bdr-s);
      padding-top: 18px;
      transition: gap 0.2s;
    }
    .cmt-action i { font-size: 1.1rem; }
    .cmt-card:hover .cmt-action { gap: 12px; color: var(--primary-2); }

    /* ========================================================================== */
    /* SPLIT-LAYOUT MODAL                                                         */
    /* ========================================================================== */
    .cmt-modal-overlay {
      display: none;
      position: fixed; inset: 0;
      background: rgba(0,14,36,0.65);
      z-index: 10000;
      align-items: center; justify-content: center;
      padding: 20px;
      backdrop-filter: blur(6px);
      -webkit-backdrop-filter: blur(6px);
    }
    .cmt-modal-overlay.open { display: flex; }

    .cmt-modal {
      width: 860px; max-width: 100%;
      background: #fff;
      border-radius: 24px;
      overflow: hidden;
      box-shadow: 0 24px 60px rgba(0,0,0,0.2);
      animation: modalPop 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      display: flex;
      flex-direction: row;
      position: relative;
    }
    @keyframes modalPop {
      from { transform: scale(0.92); opacity: 0; }
      to { transform: scale(1); opacity: 1; }
    }

    .cmt-m-top {
      width: 40%;
      min-height: 420px;
      position: relative;
      display: flex; align-items: center; justify-content: center;
      font-size: 6rem;
      background-size: cover;
      background-position: center;
      background-color: var(--primary-l);
    }
    .cmt-m-top::after {
      content: ''; position: absolute; inset: 0;
      box-shadow: inset -10px 0 20px rgba(0,0,0,0.03);
      pointer-events: none;
    }

    .cmt-m-body { 
      width: 60%;
      padding: 48px 40px; 
      background: #fff; 
      overflow-y: auto;
      max-height: 85vh;
      position: relative;
    }

    .cmt-m-close {
      position: absolute; top: 20px; right: 20px;
      width: 36px; height: 36px; border-radius: 50%;
      background: var(--sur-2); color: var(--text-s); 
      border: 1px solid var(--bdr);
      display: flex; align-items: center; justify-content: center;
      cursor: pointer; font-size: 1.1rem; z-index: 10;
      transition: all 0.2s;
    }
    .cmt-m-close:hover { background: var(--error); color: #fff; border-color: var(--error); transform: rotate(90deg); }

    .cmt-m-title {
      font-size: 1.8rem; font-weight: 800; color: var(--primary-d);
      margin: 16px 0 24px 0; line-height: 1.25; font-family: 'DM Sans', sans-serif;
    }

    /* Member List styling in Modal */
    .modal-member-list { padding: 0; margin: 0; list-style: none; }
    .member-row { 
      display: flex; align-items: center; justify-content: space-between; 
      padding: 16px 0; border-bottom: 1px solid var(--bdr-s); 
    }
    .member-row:last-child { border-bottom: none; padding-bottom: 0; }

    .member-name { 
      font-size: 1rem; font-weight: 700; color: var(--primary-d); 
      display: flex; align-items: center; gap: 14px; 
    }
    .member-icon { 
      width: 40px; height: 40px; border-radius: 50%; 
      background: var(--digital-blue-50); color: var(--primary); 
      display: flex; align-items: center; justify-content: center; 
      font-size: 1.1rem; flex-shrink: 0; border: 1px solid rgba(0,102,255,0.05);
    }
    .member-role { 
      font-size: 0.72rem; font-weight: 800; text-transform: uppercase; 
      letter-spacing: 0.05em; padding: 4px 12px; border-radius: 50px; 
      flex-shrink: 0; text-align: center; min-width: 100px;
    }

    /* Role Colors */
    .role-chairman { background: var(--primary-d); color: #fff; }
    .role-member { background: var(--sur-2); color: var(--text-s); border: 1px solid var(--bdr); }
    .role-student { background: #d1fae5; color: #065f46; border: 1px solid #a7f3d0; }

    @media (max-width: 768px) {
      .cmt-modal { flex-direction: column; width: 92%; }
      .cmt-m-top { width: 100%; min-height: 200px; height: 200px; border-right: none; border-bottom: 1px solid var(--bdr-s); }
      .cmt-m-top::after { display: none; }
      .cmt-m-body { width: 100%; padding: 32px 24px; }
      .cmt-m-close { top: 16px; right: 16px; background: rgba(255,255,255,0.9); border-color: transparent; }
      .cmt-m-close:hover { background: #fff; color: var(--error); transform: none; }
      .cmt-m-title { font-size: 1.5rem; }
      .member-name { font-size: 0.9rem; gap: 10px; }
      .member-icon { width: 32px; height: 32px; font-size: 0.9rem; }
      .member-role { min-width: auto; padding: 4px 8px; font-size: 0.65rem; }
    }

    /* ========================================================================== */
    /* ANIMATIONS (Scroll Reveal)                                                 */
    /* ========================================================================== */
    .fade-up { opacity: 0; transform: translateY(32px); transition: opacity .6s var(--ease), transform .6s var(--ease); }
    .fade-up.visible { opacity: 1; transform: translateY(0); }
    .fade-in { opacity: 0; transition: opacity .6s var(--ease); }
    .fade-in.visible { opacity: 1; }

    .delay-1 { transition-delay: .05s; }
    .delay-2 { transition-delay: .1s; }
    .delay-3 { transition-delay: .15s; }
    .delay-4 { transition-delay: .2s; }

base_js:
/* ========================================================================== */
  /* PAGE INTERACTIONS (Scroll Reveal & Modals)                                 */
  /* ========================================================================== */
  (function () {
    'use strict';

    /* ── Scroll-Reveal (IntersectionObserver) ── */
    const revealEls = document.querySelectorAll('.fade-up, .fade-in');
    if (revealEls.length) {
      const obs = new IntersectionObserver(
        (entries) => {
          entries.forEach((entry) => {
            if (entry.isIntersecting) {
              entry.target.classList.add('visible');
              obs.unobserve(entry.target);
            }
          });
        },
        { threshold: 0.15 }
      );
      revealEls.forEach((el) => obs.observe(el));
    }

    /* ── Split-Layout Modal — Card click handler ── */
    document.querySelectorAll('.cmt-card').forEach((card) => {
      card.addEventListener('click', () => {
        document.getElementById('mIcon').textContent = card.dataset.emoji || '';
        document.getElementById('mTop').style.backgroundColor = card.dataset.bg || 'var(--primary-l)';

        document.getElementById('mTitle').textContent = card.dataset.title || '';
        document.getElementById('mBadge').textContent = card.dataset.badge || '';

        // Process Members
        const membersData = card.dataset.members;
        const memberListEl = document.getElementById('mMemberList');

        if (membersData) {
          try {
            const members = JSON.parse(membersData);
            const listHtml = members.map(m => {
              // Assign distinct styling classes based on role
              let roleClass = 'role-member';
              const roleLower = m.r.toLowerCase();
              if (roleLower.includes('chair') || roleLower.includes('presiding')) {
                roleClass = 'role-chairman';
              } else if (roleLower.includes('student')) {
                roleClass = 'role-student';
              }

              return `
                <li class="member-row">
                  <div class="member-name">
                    <div class="member-icon"><i class="bi bi-person-fill"></i></div>
                    ${m.n}
                  </div>
                  <div class="member-role ${roleClass}">${m.r}</div>
                </li>
              `;
            }).join('');
            memberListEl.innerHTML = listHtml;
          } catch (e) {
            console.error("Invalid JSON in data-members", e);
            memberListEl.innerHTML = '';
          }
        } else {
          memberListEl.innerHTML = '';
        }

        // Show Modal
        document.getElementById('cmtModalOverlay').classList.add('open');
        document.body.style.overflow = 'hidden';
      });
    });

    // Close Modal Logic
    const overlay = document.getElementById('cmtModalOverlay');
    const closeBtn = document.getElementById('mClose');

    function closeCmtModal() {
      overlay.classList.remove('open');
      document.body.style.overflow = '';
    }

    if(closeBtn) closeBtn.addEventListener('click', closeCmtModal);
    if(overlay) overlay.addEventListener('click', e => {
      if (e.target === overlay) closeCmtModal();
    });
    document.addEventListener('keydown', e => {
      if (e.key === 'Escape') closeCmtModal();
    });

  })();
